const rawPhone = $input.first().json['Phone Number'];
const phoneNumber = String(rawPhone || '');
const cleaned = phoneNumber.replace(/\D/g, '');

// Country code to timezone mapping
const timezoneMap = {
  '44': 'Europe/London',
  '1': 'America/New_York',
  '61': 'Australia/Sydney',
  '33': 'Europe/Paris',
  '49': 'Europe/Berlin',
  '34': 'Europe/Madrid',
  '39': 'Europe/Rome',
  '31': 'Europe/Amsterdam',
  '353': 'Europe/Dublin',
  '91': 'Asia/Kolkata',
  '971': 'Asia/Dubai',
  '65': 'Asia/Singapore',
  '81': 'Asia/Tokyo',
};

// Find matching country code (check longer codes first)
let timezone = 'Europe/London';
let countryCode = '44';

const sortedCodes = Object.keys(timezoneMap).sort((a, b) => b.length - a.length);
for (const code of sortedCodes) {
  if (cleaned.startsWith(code)) {
    timezone = timezoneMap[code];
    countryCode = code;
    break;
  }
}

// Get current time in the lead's timezone using Intl API
const now = new Date();

const formatter = new Intl.DateTimeFormat('en-GB', {
  timeZone: timezone,
  hour: 'numeric',
  minute: 'numeric',
  weekday: 'long',
  hour12: false
});

const parts = formatter.formatToParts(now);
const localHour = parseInt(parts.find(p => p.type === 'hour').value, 10);
const localMinute = parseInt(parts.find(p => p.type === 'minute').value, 10);
const weekdayName = parts.find(p => p.type === 'weekday').value;

const weekdayMap = {
  'Monday': 1,
  'Tuesday': 2,
  'Wednesday': 3,
  'Thursday': 4,
  'Friday': 5,
  'Saturday': 6,
  'Sunday': 7
};
const dayOfWeek = weekdayMap[weekdayName];

return {
  json: {
    ...$input.first().json,
    timezone,
    countryCode,
    localHour,
    localMinute,
    dayOfWeek,
    localTimeFormatted: `${weekdayName} ${String(localHour).padStart(2, '0')}:${String(localMinute).padStart(2, '0')}`
  }
};

const items = $input.all();
const updatedItems = items.map((item) => {
  item.json["Phone Number"] = String(item.json["Phone Number"]).replace(/\D/g, "");
  return item;
});
return updatedItems;
